#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long A,X,B,Y;
        scanf("%lld %lld %lld %lld",&A,&X,&B,&Y);
        long long left = A*Y;
        long long right = B*X;
        if(left>right) printf("ALICE\n");
        else if(left<right) printf("BOB\n");
        else printf("EQUAL\n");
    }
    return 0;
}

