import sys

def main():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        A=int(next(it)); X=int(next(it)); B=int(next(it)); Y=int(next(it))
        if A*Y > B*X:
            out.append('ALICE')
        elif A*Y < B*X:
            out.append('BOB')
        else:
            out.append('EQUAL')
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    main()

